def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[idx] = np.inf
            continue
        usage_ratio = item / capacity
        score = 40.0 + np.exp(-capacity/5) * 50
        if usage_ratio > 5:
            score += 6000 * np.log1p(usage_ratio)
            if capacity > 15:
                score += 120 * np.tanh(capacity/10) + 45 * np.cos(capacity * 0.9)
                for i in range(1, 6):
                    score += ((-1)**i)*np.sin(usage_ratio*np.pi*i*0.7)*18/i
            else:
                score -= 60 * usage_ratio
                for j in range(3):
                    score += np.random.uniform(-10,10)
        elif 4 < usage_ratio <= 5:
            diff = usage_ratio - 4
            score += 2500 * diff**2 + 300 * np.sqrt(1 - diff)
            for k in range(1, 9):
                score += np.cos(usage_ratio * np.pi * (k**1.5)) * 22 / k
            if int(capacity*4) % 5 == 0:
                score += 50 * np.tan(capacity/20)
            for l in range(2, 7):
                score -= (l**1.2) * np.log1p(capacity) / (usage_ratio + l)
        elif 3 < usage_ratio <= 4:
            base = (usage_ratio - 3)**3
            score += 1800 * base + 180 * (1 - base**0.6)
            fluct = 0
            for m in range(1, 13):
                val = usage_ratio ** m
                if val < 0.3:
                    fluct += val * 12 / m
                    if m % 3 == 0:
                        fluct -= 5 * m
                else:
                    fluct += (1 - val) * 20 / (m + 2)
                    if m == 11 and usage_ratio > 3.7:
                        fluct += 25
            score += fluct
            if capacity % 3.1 < 0.4:
                score += 40 * np.sin(capacity * 3.7)
            for n in range(1, 5):
                if (int(capacity * 200) + n) % 7 == 0:
                    score += 6 * n
                else:
                    score -= n * 3
        elif 2 < usage_ratio <= 3:
            score += 1400 * (usage_ratio - 2)**2.5
            for o in range(1, 14):
                pow_val = usage_ratio ** o
                if pow_val < 0.55:
                    score += pow_val * 18 / o
                    if o % 4 == 1:
                        score += 4 * o
                else:
                    score += (1 - pow_val) * 16 / (o + 3)
                    if o == 12 and usage_ratio > 2.6:
                        score += 22
            if capacity % 2.7 < 0.45:
                score += 45 * np.cos(capacity * 3.2)
            for p in range(1,6):
                score -= p * np.exp(-usage_ratio * 12)
        elif 1 < usage_ratio <= 2:
            score += 1100 * (usage_ratio - 1)**3.5
            fluct = 0
            for q in range(1, 20):
                power = usage_ratio ** q
                if power < 0.7:
                    fluct += power * 22 / q
                    if q % 5 == 2:
                        fluct -= 3 * q
                else:
                    fluct += (1 - power) * 14 / (q + 2)
                    if q == 16 and usage_ratio > 1.8:
                        fluct += 18
            score += fluct
            if capacity % 1.3 < 0.35:
                score += 35 * np.sin(capacity * 2.3)
            for r in range(1, 7):
                score -= r * np.exp(-usage_ratio * 18)
        elif 0.4 < usage_ratio <= 1:
            score += 160 * (1 - usage_ratio)**1.2
            fluct = 0
            for s in range(1, 12):
                ratio_pow = usage_ratio ** s
                fluct += (np.tanh(ratio_pow * np.pi / 2) - 0.35) * 11 / s
                if usage_ratio < 0.06 * s:
                    fluct -= 6 * s
            score += fluct
            if capacity < 0.1:
                score += np.sqrt(capacity) * 300
            elif capacity < 0.8:
                score += np.log1p(capacity * 22) * 40
            else:
                score += (capacity % 6) * 24
        else:
            score += 320 * (1 - usage_ratio)**2.3
            for t in range(1, 20):
                ratio_pow = usage_ratio ** t
                score += (np.sin(ratio_pow * np.pi / 7) - 0.28) * 14 / t
                if usage_ratio < 0.012 * t:
                    score -= 14 * t
            if capacity < 0.01:
                score += np.sqrt(capacity) * 400
            elif capacity < 1.05:
                score += np.log1p(capacity * 28) * 50
            else:
                score += (capacity % 7) * 35
        if capacity < 0.03:
            score += 80
            if usage_ratio > 0.8:
                score += 100
            elif usage_ratio < 0.15:
                score -= 60
                for u in range(1, 8):
                    score -= u * np.exp(-usage_ratio * 25)
        elif capacity < 0.95:
            score += 45
            if usage_ratio > 0.9:
                score += 70
            elif usage_ratio < 0.22:
                score -= 35
            for v in range(1, 7):
                if int(capacity * 1400) % (v + 5) == 0:
                    score += v * 8
                else:
                    score -= v * 4
        else:
            if usage_ratio < 0.1:
                score -= 50
                for w in range(1, 8):
                    score -= w * 6
            elif usage_ratio > 0.94:
                score += 100
                for x in range(1, 6):
                    score += x * 12
            else:
                score += 35
        prox = 0
        if int(capacity * 3000) % 23 == 0:
            prox += 18
        if int(capacity * 1100) % 29 == 0:
            prox -= 14
        if int(capacity * 200) % 11 == 0:
            prox += 16
        for y in range(1, 11):
            diff = abs(usage_ratio - y / 11)
            if diff < 0.015:
                prox += 24 / y
            elif diff < 0.04:
                prox += 14 / y
            else:
                prox -= 5 / y
        for z in range(1, 9):
            mod_check = int(capacity * 1800) % (z + 11)
            if mod_check == 0:
                prox += z * 6
            elif mod_check == 4:
                prox -= z * 5
        for aa in range(1, 6):
            mod_check = int(usage_ratio * 1800) % (aa + 8)
            if mod_check == 0:
                prox += 14 * aa
            elif mod_check == 4:
                prox -= 10 * aa
        score += prox
        if usage_ratio < 0.007:
            for bb in range(1, 9):
                score -= bb * 12
        elif usage_ratio > 0.97:
            for cc in range(1, 8):
                score += cc * 14
        if capacity > 3.0:
            if capacity % 1 < 0.04:
                score += 50
            if (int(capacity * 3000) % 29 == 0) and (usage_ratio > 0.75):
                score += 75
            for dd in range(1, 7):
                if (int(capacity * 700) % (dd + 11) == 3) and (usage_ratio < 0.9):
                    score -= 30
        if np.isnan(score) or np.isinf(score):
            score = 3e4
        if abs(score) > 3e4:
            score = np.sign(score) * 3e4
        priorities[idx] = score
    return priorities
